if (!function_exists('prod_t')) {
  function prod_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('prod_h')) {
  function prod_h($key, $fallback = '') { return htmlspecialchars((string) prod_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('prod_js')) {
  function prod_js($key, $fallback = '') { return json_encode(prod_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom=date('Y-m-01');$defaultTo=date('Y-m-d');
$plants=$db->query("SELECT DISTINCT plant AS plant_code FROM production_order WHERE plant IS NOT NULL AND plant<>'' ORDER BY plant");
$kpi=$db->fetch("SELECT COUNT(*) total_wip,SUM(status='RELEASED') released_order,SUM(status='IN_PROCESS') in_process_order,SUM(status='CONFIRMED') confirmed_order FROM production_order WHERE status IN ('RELEASED','IN_PROCESS','CONFIRMED','TECO') AND start_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
$flow=$db->fetch("SELECT COALESCE(SUM(conf.yield_qty),0) yield_qty,COALESCE(SUM(gr.gr_qty),0) gr_qty FROM production_order p LEFT JOIN (SELECT id_production_order,SUM(CASE WHEN status='POSTED' THEN yield_qty ELSE 0 END) yield_qty FROM production_order_confirmation GROUP BY id_production_order) conf ON conf.id_production_order=p.id_production_order LEFT JOIN (SELECT h.id_production_order,SUM(CASE WHEN h.status='POSTED' THEN d.qty ELSE 0 END) gr_qty FROM erp_gr_production h JOIN erp_gr_production_detail d ON d.gr_id=h.id GROUP BY h.id_production_order) gr ON gr.id_production_order=p.id_production_order WHERE p.status IN ('RELEASED','IN_PROCESS','CONFIRMED','TECO') AND p.start_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
?>
