<script>
function wipError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_wip_monitoring_process_failed', 'WIP Monitoring failed to process.');?>);$('.error_data_delete').fadeIn();}
function wipFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),status:$('#filter_status').val(),plant:$('#filter_plant').val(),wip_state:$('#filter_wip_state').val(),keyword:$('#filter_keyword').val()};}
function wipQuery(){return $.param(wipFilters());}
$(function(){if($.fn.datepicker){$('.wip-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_status,#filter_plant,#filter_wip_state').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_wip_monitoring').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'58px',targets:1},{className:'wip-progress',targets:7}],ajax:{url:'<?=base_admin();?>modul/wip_monitoring/wip_monitoring_data.php',type:'post',data:function(d){$.extend(d,wipFilters());},error:function(xhr){console.log(xhr.responseText);wipError(<?=prod_js('production_wip_load_failed', 'WIP data failed to load.');?>);}}});
$('#btn_filter_wip').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_wip').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_status,#filter_plant,#filter_wip_state').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_wip,#btn_excel_wip_top').click(function(){window.location='<?=base_admin();?>modul/wip_monitoring/wip_monitoring_action.php?act=excel&'+wipQuery();});
$(document).on('click','.btn-wip-detail',function(){$.post('<?=base_admin();?>modul/wip_monitoring/wip_monitoring_action.php?act=detail',{id:$(this).data('id')},function(html){$('#wip_detail_body').html(html);$('#modal_detail_wip').modal('show');}).fail(function(){wipError('Detail WIP gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
